import{_ as a,o as t,c as i,a2 as s}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"缓存 Key、TTL、命中率、随机过期与容量治理","description":"","frontmatter":{"stage":"intermediate","direction":"backend-data","topic":"cache-key-ttl-hit-rate"},"headers":[],"relativePath":"05-backend-data/notes/cache-messaging-storage/03-cache-key-ttl-hit-rate.md","filePath":"05-backend-data/notes/cache-messaging-storage/03-cache-key-ttl-hit-rate.md","lastUpdated":1784261650000}'),l={name:"05-backend-data/notes/cache-messaging-storage/03-cache-key-ttl-hit-rate.md"};function n(r,e,o,d,c,p){return t(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="缓存-key、ttl、命中率、随机过期与容量治理" tabindex="-1">缓存 Key、TTL、命中率、随机过期与容量治理 <a class="header-anchor" href="#缓存-key、ttl、命中率、随机过期与容量治理" aria-label="Permalink to &quot;缓存 Key、TTL、命中率、随机过期与容量治理&quot;">​</a></h1><p>缓存可维护性取决于 key 是否稳定表达数据边界、TTL 是否匹配陈旧预算、命中率是否按真实请求权重解释，以及内存/淘汰是否在故障前可观测。只设置一个统一 TTL 无法形成可靠策略。</p><h2 id="_1-key-是缓存契约" tabindex="-1">1. Key 是缓存契约 <a class="header-anchor" href="#_1-key-是缓存契约" aria-label="Permalink to &quot;1. Key 是缓存契约&quot;">​</a></h2><p>key 同时决定身份、隔离、路由、失效和观测。建议结构：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;domain&gt;:&lt;schema-version&gt;:&lt;tenant&gt;:&lt;entity&gt;:&lt;id&gt;:&lt;variant&gt;</span></span>
<span class="line"><span>catalog:v3:t_7:product:p_9:locale:zh-CN</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>逐段含义：</p><ul><li>domain 避免不同业务碰撞，并用于 ACL/监控分组。</li><li>schema version 隔离不兼容序列化格式。</li><li>tenant 从可信认证上下文取得，防跨租户复用。</li><li>entity/id 指向事实对象，不把可变标题当身份。</li><li>variant 包含 locale、货币、实验组等真正改变表示的输入。</li></ul><p>key 不应含密码、token、邮箱等敏感数据；SLOWLOG、MONITOR、备份和运维工具可能看到它。必要时对标识做稳定不可逆映射，但仍要支持按事件定位失效。</p><h2 id="_2-redis-cluster-hash-slot" tabindex="-1">2. Redis Cluster hash slot <a class="header-anchor" href="#_2-redis-cluster-hash-slot" aria-label="Permalink to &quot;2. Redis Cluster hash slot&quot;">​</a></h2><p>Cluster 对 key 计算 CRC16 后映射到 16384 slots。多 key 原子命令通常要求同 slot。hash tag 使用第一个非空 <code>{...}</code> 内容：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cart:{t7:u9}:items</span></span>
<span class="line"><span>cart:{t7:u9}:summary</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>只给必须一起操作的同一购物车加 tag。把 <code>{tenant}</code> 放所有 key 会让大租户集中一个 slot；把常量 <code>{cache}</code> 放全部 key 会彻底破坏分片。迁移 key schema 要考虑新旧 slot 和双读成本。</p><h2 id="_3-ttl-的三种语义" tabindex="-1">3. TTL 的三种语义 <a class="header-anchor" href="#_3-ttl-的三种语义" aria-label="Permalink to &quot;3. TTL 的三种语义&quot;">​</a></h2><h3 id="新鲜期" tabindex="-1">新鲜期 <a class="header-anchor" href="#新鲜期" aria-label="Permalink to &quot;新鲜期&quot;">​</a></h3><p>在该时间内允许直接返回，不主动验证事实源。</p><h3 id="最大陈旧期" tabindex="-1">最大陈旧期 <a class="header-anchor" href="#最大陈旧期" aria-label="Permalink to &quot;最大陈旧期&quot;">​</a></h3><p>依赖失败时允许返回旧值的 hard deadline。不是所有数据都允许 stale。</p><h3 id="保留期" tabindex="-1">保留期 <a class="header-anchor" href="#保留期" aria-label="Permalink to &quot;保留期&quot;">​</a></h3><p>对象在 Redis 中最多保留多久，用于内存和隐私治理；它可能长于新鲜期。</p><p>单个 Redis TTL 只能表达“key 何时消失”，不能同时表达 fresh/hard 两个边界。需要在 value 保存 <code>refreshed_at</code>/version，或用两个 key/元数据。</p><h2 id="_4-绝对过期与滑动过期" tabindex="-1">4. 绝对过期与滑动过期 <a class="header-anchor" href="#_4-绝对过期与滑动过期" aria-label="Permalink to &quot;4. 绝对过期与滑动过期&quot;">​</a></h2><p>绝对 TTL 在写入时确定，到期后消失，适合验证码、价格快照。滑动 TTL 每次访问续期，适合闲置会话；若每次 GET 都续期，会让高频 key 永不淘汰并增加写/复制压力。</p><p>会话同时需要 idle timeout 和 absolute lifetime：活跃不能让被盗 session 永久有效。Redis TTL 可管理 idle，值中保存 absolute expiry，由服务端每次验证。</p><h2 id="_5-redis-过期行为" tabindex="-1">5. Redis 过期行为 <a class="header-anchor" href="#_5-redis-过期行为" aria-label="Permalink to &quot;5. Redis 过期行为&quot;">​</a></h2><p><code>EXPIRE</code>/<code>PEXPIRE</code> 设置相对时间，<code>EXPIREAT</code>/<code>PEXPIREAT</code> 设置绝对 Unix 时间，<code>TTL</code>/<code>PTTL</code> 返回剩余时间。返回值要区分 key 不存在和无过期。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SET catalog:v3:t7:p9 &#39;{...}&#39; EX 300</span></span>
<span class="line"><span>EXPIRE catalog:v3:t7:p9 600 GT</span></span>
<span class="line"><span>PTTL catalog:v3:t7:p9</span></span>
<span class="line"><span>PERSIST catalog:v3:t7:p9</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>NX/XX/GT/LT 条件能限制何时修改 TTL。具体组合按命令文档和客户端版本验证。</p><p>过期由两条路径完成：访问到已过期 key 时惰性删除，以及后台主动采样过期。到达 TTL 不保证内存物理上在同一毫秒释放；逻辑读取会把已过期 key 当不存在。大量同刻过期仍会增加 CPU 和回源。</p><h2 id="_6-随机过期-jitter" tabindex="-1">6. 随机过期 jitter <a class="header-anchor" href="#_6-随机过期-jitter" aria-label="Permalink to &quot;6. 随机过期 jitter&quot;">​</a></h2><p>若基础 TTL 为 <code>T</code>，可以在安全陈旧预算内加入随机量：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ttl = T × random(0.8, 1.2)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>jitter 目标是打散同批 key 的过期时间，不是掩盖没有回源保护。范围必须受业务最大陈旧期约束；验证码、签名等严格到期数据不能随意延长。</p><p>随机源无需密码学强度，但同一批实例不能固定相同 seed 产生相同序列。可使用稳定 hash(key) 映射抖动，保证重建时分布稳定。</p><h2 id="_7-ttl-选择方法" tabindex="-1">7. TTL 选择方法 <a class="header-anchor" href="#_7-ttl-选择方法" aria-label="Permalink to &quot;7. TTL 选择方法&quot;">​</a></h2><p>输入：允许陈旧时间、更新频率、读取频率、回源成本、内存预算、失效事件可靠性。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>候选 TTL ≤ 业务最大陈旧期</span></span>
<span class="line"><span>候选 TTL ≈ 能把回源 QPS 控制在事实源余量内的值</span></span>
<span class="line"><span>候选 TTL × 活跃 key 写入速率 ≈ 同时驻留 key 数量</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>低频大对象可能直到 TTL 都未再次访问，缓存收益小；高频极热对象适合 refresh-ahead。更新频率高于读取频率的数据不适合缓存，维护成本超过命中收益。</p><h2 id="_8-命中率的精确定义" tabindex="-1">8. 命中率的精确定义 <a class="header-anchor" href="#_8-命中率的精确定义" aria-label="Permalink to &quot;8. 命中率的精确定义&quot;">​</a></h2><p>请求命中率：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>request_hit_rate = hits / (hits + misses)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>字节命中率：命中的响应字节 / 总请求响应字节。成本加权命中率：避免的事实源成本 / 无缓存时总成本。不同指标回答不同问题。</p><p>Redis <code>keyspace_hits</code>/<code>keyspace_misses</code> 是实例级命令统计，不一定等于业务缓存请求：EXISTS、脚本、不同 DB/业务会混入。应用按 cache name、结果状态和规范化路由记录指标，但 label 不用原始 key。</p><h3 id="为什么高命中率仍可能失败" tabindex="-1">为什么高命中率仍可能失败 <a class="header-anchor" href="#为什么高命中率仍可能失败" aria-label="Permalink to &quot;为什么高命中率仍可能失败&quot;">​</a></h3><ul><li>99% hit 的 1% miss 集中在一个高成本查询。</li><li>L1 hit 掩盖 L2 大量 miss。</li><li>negative cache hit 被当成功，却掩盖过度查询不存在 ID。</li><li>stale hit 被计为 fresh hit。</li><li>热 key 命中高，但单节点网络/CPU 饱和。</li></ul><p>至少拆分 fresh_hit、stale_hit、negative_hit、cold_miss、expired_miss、evicted_miss、error。</p><h2 id="_9-memory-与-eviction" tabindex="-1">9. Memory 与 eviction <a class="header-anchor" href="#_9-memory-与-eviction" aria-label="Permalink to &quot;9. Memory 与 eviction&quot;">​</a></h2><p><code>maxmemory</code> 控制用于数据集的内存阈值，复制/AOF buffers 的部分内存不计入 eviction 比较；为系统、fork copy-on-write、buffers 和 allocator 留余量。</p><p>常见策略：</p><table tabindex="0"><thead><tr><th>策略</th><th>候选</th><th>适用</th><th>风险</th></tr></thead><tbody><tr><td><code>noeviction</code></td><td>不淘汰</td><td>不能丢的 Redis 数据</td><td>新写报错，需严格容量</td></tr><tr><td><code>allkeys-lru</code></td><td>全 key 近似 LRU</td><td>普通缓存</td><td>不等于精确 LRU</td></tr><tr><td><code>allkeys-lfu</code></td><td>全 key 近似频率</td><td>稳定热点</td><td>新热点升温速度需测</td></tr><tr><td><code>allkeys-random</code></td><td>全 key 随机</td><td>访问近均匀</td><td>可能删热 key</td></tr><tr><td><code>volatile-ttl</code></td><td>有 TTL 且最短</td><td>应用能给价值型 TTL</td><td>无 TTL key 不淘汰</td></tr><tr><td><code>volatile-*</code></td><td>仅带 TTL</td><td>混合数据</td><td>无候选时表现近 noeviction</td></tr></tbody></table><p>缓存和不可淘汰 Stream/session 混在同实例会让策略难以满足两类目标，优先拆部署。</p><h2 id="_10-过期与淘汰不是同一原因" tabindex="-1">10. 过期与淘汰不是同一原因 <a class="header-anchor" href="#_10-过期与淘汰不是同一原因" aria-label="Permalink to &quot;10. 过期与淘汰不是同一原因&quot;">​</a></h2><ul><li>expired：业务 TTL 到期，通常预期行为。</li><li>evicted：内存压力下按 policy 删除，可能提前于 TTL。</li></ul><p>若 miss 增加，分别看 <code>expired_keys</code> 与 <code>evicted_keys</code>。eviction 持续说明 working set 超容量、策略不匹配或大 key；盲目加长 TTL 会更糟。expired 高可能是正常更新，也可能 TTL 过短导致 thrash。</p><h2 id="_11-容量估算" tabindex="-1">11. 容量估算 <a class="header-anchor" href="#_11-容量估算" aria-label="Permalink to &quot;11. 容量估算&quot;">​</a></h2><p>抽样 <code>MEMORY USAGE key SAMPLES n</code>，按 key 类型/大小分桶。粗略：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dataset ≈ Σ(active_keys_per_class × p95_bytes_per_key)</span></span>
<span class="line"><span>required_RAM ≈ dataset / target_utilization + buffers + COW_headroom</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>用 p95 而非平均避免长尾低估。RDB/AOF rewrite 和主从同步可能出现额外内存/网络峰值。容量测试要包含真实 key 长度、序列化、TTL 元数据和 allocator。</p><h2 id="_12-大-key-与热-key" tabindex="-1">12. 大 Key 与热 Key <a class="header-anchor" href="#_12-大-key-与热-key" aria-label="Permalink to &quot;12. 大 Key 与热 Key&quot;">​</a></h2><p>大 key 指值/成员多导致单命令、复制、迁移或删除昂贵；热 key 指访问集中导致单分片 CPU/网络热点。它们可能是不同 key。</p><p>治理：</p><ul><li>大 String 拆按访问边界，不按固定字节随意切。</li><li>大 Hash/Set/ZSet 按实体或时间桶拆分，维护跨桶查询上限。</li><li>热只读可 L1、客户端缓存或副本读（接受一致性限制）。</li><li>热写计数可分片计数再聚合，但精确实时值成本上升。</li><li>删除大 key 用 UNLINK，并在低峰限速；仍监控后台释放。</li></ul><p>使用 <code>SCAN</code>/<code>--bigkeys</code> 生产巡检要限速；<code>KEYS *</code> 会阻塞扫描整个 keyspace。</p><h2 id="_13-keyspace-notification-边界" tabindex="-1">13. Keyspace notification 边界 <a class="header-anchor" href="#_13-keyspace-notification-边界" aria-label="Permalink to &quot;13. Keyspace notification 边界&quot;">​</a></h2><p>Redis 可发布 key 事件通知，但需要配置，使用 Pub/Sub，消费者断线会漏事件，且通知本身增加开销。它适合触发辅助动作，不适合作为唯一可靠业务事件源。可靠失效使用数据库 outbox/持久 Stream/Kafka，再配 TTL 收敛。</p><h2 id="_14-应用案例一-日报表缓存" tabindex="-1">14. 应用案例一：日报表缓存 <a class="header-anchor" href="#_14-应用案例一-日报表缓存" aria-label="Permalink to &quot;14. 应用案例一：日报表缓存&quot;">​</a></h2><h3 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>每个租户的日报表查询 3 秒；报表在当天持续变化，历史日冻结；工作日 09:00 大量用户同时打开。允许当天数据陈旧 60 秒，历史数据 24 小时。</p><h3 id="处理" tabindex="-1">处理 <a class="header-anchor" href="#处理" aria-label="Permalink to &quot;处理&quot;">​</a></h3><ol><li>key：<code>report:v2:{tenant}:daily:2026-07-17:tz:Asia-Shanghai</code>。</li><li>当天 fresh TTL 45–60 秒，hard stale 120 秒；历史 TTL 24 小时 ±20%。</li><li>08:55 后台只预热最近活跃租户，并设全局并发/数据库 QPS 上限。</li><li>miss 用跨实例租约 + 数据库容量闸门；未持租约者短暂返回 stale 或等待。</li><li>报表修正事件按 tenant/date 删除；TTL 作为漏事件后的上界。</li></ol><h3 id="输出与验证" tabindex="-1">输出与验证 <a class="header-anchor" href="#输出与验证" aria-label="Permalink to &quot;输出与验证&quot;">​</a></h3><p>按 tenant tier 记录 hit/miss/fill；09:00 数据库 QPS 不超过预算；历史 key 的 byte hit 高。随机暂停失效 consumer，120 秒内当天数据仍收敛。</p><h3 id="失败注入" tabindex="-1">失败注入 <a class="header-anchor" href="#失败注入" aria-label="Permalink to &quot;失败注入&quot;">​</a></h3><p>清空 Redis 后受控预热，不让所有用户并发生成报表。若租约持有者崩溃，短 TTL 释放；数据库闸门继续保护事实源。</p><h2 id="_15-应用案例二-一次性下载-token" tabindex="-1">15. 应用案例二：一次性下载 token <a class="header-anchor" href="#_15-应用案例二-一次性下载-token" aria-label="Permalink to &quot;15. 应用案例二：一次性下载 token&quot;">​</a></h2><h3 id="输入-1" tabindex="-1">输入 <a class="header-anchor" href="#输入-1" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>token 必须 10 分钟到期且只能消费一次；Redis failover 可能丢最近写；下载权限敏感。</p><h3 id="方案与取舍" tabindex="-1">方案与取舍 <a class="header-anchor" href="#方案与取舍" aria-label="Permalink to &quot;方案与取舍&quot;">​</a></h3><p>仅 Redis <code>GETDEL</code> 提供单节点命令原子，但异步复制 failover 可能让已消费 token 在旧副本状态中重新出现，或刚创建 token 丢失。若业务不能接受重放，应把消费记录/nonce 唯一约束放 PostgreSQL，Redis 只做加速拒绝。</p><ol><li>数据库保存 token hash、expires_at、consumed_at。</li><li>Redis 缓存“可能有效”10 分钟，key 不含原 token。</li><li>消费事务执行 <code>UPDATE ... WHERE consumed_at IS NULL AND expires_at &gt; now()</code>。</li><li>成功后删除缓存；失败返回统一错误防枚举。</li></ol><h3 id="验证与失败注入" tabindex="-1">验证与失败注入 <a class="header-anchor" href="#验证与失败注入" aria-label="Permalink to &quot;验证与失败注入&quot;">​</a></h3><p>并发消费 100 次只有一个数据库 UPDATE 成功。Redis 在消费前后 failover，不会让第二次下载通过。严格时间由数据库时钟判断，随机 TTL 不得延长安全到期。</p><h2 id="_16-应用案例三-schema-版本切换" tabindex="-1">16. 应用案例三：Schema 版本切换 <a class="header-anchor" href="#_16-应用案例三-schema-版本切换" aria-label="Permalink to &quot;16. 应用案例三：Schema 版本切换&quot;">​</a></h2><h3 id="输入-2" tabindex="-1">输入 <a class="header-anchor" href="#输入-2" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>商品缓存 v2 使用 <code>price</code> 浮点元，v3 使用 <code>price_cents</code> 整数；滚动发布 30 分钟。</p><h3 id="处理-1" tabindex="-1">处理 <a class="header-anchor" href="#处理-1" aria-label="Permalink to &quot;处理&quot;">​</a></h3><ol><li>新代码读写 <code>catalog:v3...</code>，miss 时查数据库；不覆盖 v2。</li><li>旧代码继续使用 v2；数据库是共同事实源。</li><li>控制 v3 预热速率，观察 memory 双份峰值。</li><li>旧实例归零后让 v2 按 TTL 淘汰，不执行 KEYS 全删。</li><li>回滚只切回仍被维护的 v2；若新写语义不能无损转换，先禁用新功能。</li></ol><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>两个版本并存不发生反序列化错误；内存峰值在容量内；回滚窗口结束前 v2 更新链路仍工作。</p><h2 id="_17-调试与告警" tabindex="-1">17. 调试与告警 <a class="header-anchor" href="#_17-调试与告警" aria-label="Permalink to &quot;17. 调试与告警&quot;">​</a></h2><p>指标至少包括：</p><ul><li>fresh/stale/negative hit rate；</li><li>miss 原因和 fill p95/p99；</li><li>key 数、dataset bytes、RSS、fragmentation；</li><li>expired/s、evicted/s、rejected writes；</li><li>hot key command QPS、网络字节；</li><li>DB fallback QPS 与限流拒绝；</li><li>schema 版本 key 比例；</li><li>TTL 分布而非单个平均。</li></ul><p>告警要基于持续时间和业务影响。短时 eviction 在批量加载期间可能正常，持续 eviction + DB QPS/p99 上升才是高风险链路。</p><h2 id="_18-生产检查" tabindex="-1">18. 生产检查 <a class="header-anchor" href="#_18-生产检查" aria-label="Permalink to &quot;18. 生产检查&quot;">​</a></h2><ol><li>每类 key 有 owner、schema、TTL、事实源和删除策略。</li><li>过期 jitter 不突破安全/业务截止时间。</li><li>eviction policy 与实例用途一致。</li><li>key 不含 secret/PII，ACL 限制业务前缀。</li><li>冷启动/清库/节点故障做过容量演练。</li><li>SCAN、大 key 删除和批量写有速率限制。</li><li>缓存 miss 不能绕过授权或业务校验。</li><li>删除请求覆盖所有版本 key 与 CDN。</li></ol><h2 id="_19-综合练习与验收" tabindex="-1">19. 综合练习与验收 <a class="header-anchor" href="#_19-综合练习与验收" aria-label="Permalink to &quot;19. 综合练习与验收&quot;">​</a></h2><p>为商品、日报表、会话和一次性 token 分别设计 key/TTL/eviction。输出容量模型、TTL 分布、Cluster slot 设计和故障矩阵。</p><p>验收标准：报表缓存清空时数据库不超预算；会话同时有 idle/absolute expiry；一次性 token 的最终单次消费由数据库保证；v2→v3 滚动发布可回退；指标能把 expired、evicted、error miss 分开；大 key 和热 key 各有独立治理方案。</p><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://redis.io/docs/latest/commands/expire/" target="_blank" rel="noreferrer">Redis EXPIRE</a>（访问日期：2026-07-17）</li><li><a href="https://redis.io/docs/latest/develop/reference/eviction/" target="_blank" rel="noreferrer">Redis key eviction</a>（访问日期：2026-07-17）</li><li><a href="https://redis.io/docs/latest/operate/oss_and_stack/reference/cluster-spec/" target="_blank" rel="noreferrer">Redis Cluster specification</a>（访问日期：2026-07-17）</li><li><a href="https://redis.io/docs/latest/operate/oss_and_stack/management/optimization/memory-optimization/" target="_blank" rel="noreferrer">Redis memory optimization</a>（访问日期：2026-07-17）</li><li><a href="https://redis.io/docs/latest/develop/pubsub/keyspace-notifications/" target="_blank" rel="noreferrer">Redis keyspace notifications</a>（访问日期：2026-07-17）</li></ul>`,99)])])}const b=a(l,[["render",n]]);export{u as __pageData,b as default};
